module top_module(
    Q  ,
    CLK,
    D  ,
    SCD,
    SCE
);output Q  ;
    input  CLK;
    input  D  ;
    input  SCD;
    input  SCE;


reg r_reg;
wire mux_out;
assign mux_out = (SCE == 1'b1)? SCD : D;

always @ ( posedge CLK)
       begin
	     r_reg <= mux_out;
       end

assign Q = r_reg;

endmodule
